#include<bits/stdc++.h>
using namespace std;
const long long mod=10007;
long long a[300010],mul_tag[300010],blksiz,blk[300010],blkl[300010],blkr[300010],add_tag[300010];
void pushadd(long long x,long long v)
{
    add_tag[x]+=v;
    add_tag[x]%=mod;
}
void pushmul(long long x,long long v)
{
    mul_tag[x]*=v;
    mul_tag[x]%=mod;
    add_tag[x]*=v;
    add_tag[x]%=mod;
}
void pushdown(long long x)
{
    for(long long i=blkl[x];i<=blkr[x];i++)
    {
        a[i]*=mul_tag[x];
        a[i]%=mod;
        a[i]+=add_tag[x];
        a[i]%=mod;
    }
    mul_tag[x]=1;
    add_tag[x]=0;
}
void add(long long l,long long r,long long v)
{
    if(blk[l]==blk[r])
    {
        pushdown(blk[l]);
        for(long long i=l;i<=r;i++)
        {
            a[i]+=v;
            a[i]%=mod;
        }
        return;
    }
    pushdown(blk[l]);
    for(long long i=l;i<=blkr[blk[l]];i++)
    {
        a[i]+=v;
        a[i]%=mod;
    }
    pushdown(blk[r]);
    for(long long i=blkl[blk[r]];i<=r;i++)
    {
        a[i]+=v;
        a[i]%=mod;
    }
    for(long long i=blk[l]+1;i<blk[r];i++)
    {
        pushadd(i,v);
    }
}
void mul(long long l,long long r,long long v)
{
    if(blk[l]==blk[r])
    {
        pushdown(blk[l]);
        for(long long i=l;i<=r;i++)
        {
            a[i]=a[i]*v%mod;
        }
        return;
    }
    pushdown(blk[l]);
    for(long long i=l;i<=blkr[blk[l]];i++)
    {
        a[i]=a[i]*v%mod;
    }
    pushdown(blk[r]);
    for(long long i=blkl[blk[r]];i<=r;i++)
    {
        a[i]=a[i]*v%mod;
    }
    for(long long i=blk[l]+1;i<blk[r];i++)
    {
        pushmul(i,v);
    }
}
int main()
{
    long long n;
    scanf("%lld",&n);
    blksiz=sqrt(n);
    for(long long i=1;blksiz*(i-1)+1<=n;i++)
    {
        blkl[i]=blksiz*(i-1)+1;
        blkr[i]=min(n,blksiz*i);
        mul_tag[i]=1;
    }
    for(long long i=1;i<=n;i++)
    {
        scanf("%lld",&a[i]);
        blk[i]=(i+blksiz-1)/blksiz;
    }
    while(n--)
    {
        long long op,l,r,c;
        scanf("%lld%lld%lld%lld",&op,&l,&r,&c);
        if(op==0)
        {
            add(l,r,c);
        }
        else if(op==1)
        {
            mul(l,r,c);
        }
        else
        {
            pushdown(blk[r]);
            printf("%lld\n",(a[r]%mod+mod)%mod);
        }
    }
    return 0;
}
